import { useEffect, useState } from "react";
import axios from "axios";

function Dashboard() {
    const role = localStorage.getItem("role");
    const [stats, setStats] = useState({
        total_leads: 0,
        active_users: 0,
        pending_tasks: 0,
        recent_activity: []
    });

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const token = localStorage.getItem("token");
                const res = await axios.get("http://localhost:8000/dashboard-stats", {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setStats(res.data);
            } catch (err) {
                console.error("Error fetching dashboard stats", err);
            }
        };
        fetchStats();
    }, []);

    return (
        <div className="container mt-4">
            <div className="text-center mb-4">
                <h2 className="fw-bold">Dashboard</h2>
                <p className="text-muted">Overview of your activities</p>
            </div>

            {(role === "agent" || role === "admin") && (
                <div className="alert alert-primary text-center shadow-sm">
                    <h5 className="mb-0">
                        👋 Welcome back, {role.charAt(0).toUpperCase() + role.slice(1)}!
                    </h5>
                </div>
            )}

            {/* Dashboard Cards */}
            <div className="row mt-4">
                <div className="col-md-4 mb-3">
                    <div className="card text-white bg-primary shadow-sm">
                        <div className="card-body text-center">
                            <h5 className="card-title">Total Leads</h5>
                            <p className="card-text fs-4 fw-bold">{stats.total_leads}</p>
                        </div>
                    </div>
                </div>

                <div className="col-md-4 mb-3">
                    <div className="card text-white bg-success shadow-sm">
                        <div className="card-body text-center">
                            <h5 className="card-title">Active Users</h5>
                            <p className="card-text fs-4 fw-bold">{stats.active_users}</p>
                        </div>
                    </div>
                </div>

                <div className="col-md-4 mb-3">
                    <div className="card text-white bg-warning shadow-sm">
                        <div className="card-body text-center">
                            <h5 className="card-title">Pending Tasks</h5>
                            <p className="card-text fs-4 fw-bold">{stats.pending_tasks}</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Recent Activity */}
            <div className="card mt-4 shadow-sm">
                <div className="card-header bg-dark text-white">
                    Recent Activity
                </div>
                <ul className="list-group list-group-flush">
                    {stats.recent_activity.length > 0 ? (
                        stats.recent_activity.map((act, idx) => (
                            <li key={idx} className="list-group-item">{act}</li>
                        ))
                    ) : (
                        <li className="list-group-item text-muted">No recent activity</li>
                    )}
                </ul>
            </div>
        </div>
    );
}

export default Dashboard;
